NS         = "http://www.infocamere.it/itnn/fr/itcc/ci/2018-11-04"
docs_dir   = os.environ.get("DOCUMENTS_DIR", ".")
output_dir = os.environ.get("OUTPUT_DIR",    docs_dir)
os.makedirs(output_dir, exist_ok=True)

def _anno_da_nome(nome):
    m = re.search(r"(20\d{2})", nome)
    return int(m.group(1)) if m else None

file_anni = {}
for f in sorted(os.listdir(docs_dir)):
    if f.lower().endswith(".xbrl"):
        a = _anno_da_nome(f)
        if a:
            file_anni[a] = f

if not file_anni:
    raise FileNotFoundError(f"Nessun file .xbrl trovato in '{docs_dir}'.")

anni       = sorted(file_anni.keys())
anni_label = f"{anni[0]}–{anni[-1]}"
ultimo     = anni[-1]
print(f"File rilevati: {sorted(file_anni.items())}")

# ==================== TAG XBRL ====================
TAGS = {
    # ── Stato Patrimoniale Attivo ──
    "Crediti vs Soci":              (["TotaleCreditiVersoSociVersamentiAncoraDovuti"],                                                    "i"),
    "Imm. Immateriali":             (["TotaleImmobilizzazioniImmateriali"],                                                               "i"),
    "Imm. Materiali":               (["TotaleImmobilizzazioniMateriali"],                                                                 "i"),
    "Imm. Finanziarie":             (["TotaleImmobilizzazioniFinanziarie"],                                                               "i"),
    "Tot. Immobilizzazioni":        (["TotaleImmobilizzazioni"],                                                                          "i"),
    "Rimanenze":                    (["TotaleRimanenze"],                                                                                 "i"),
    "Crediti Totali":               (["TotaleCrediti"],                                                                                   "i"),
    "Liquidita":                    (["TotaleDisponibilitaLiquide"],                                                                      "i"),
    "Tot. Attivo Circolante":       (["TotaleAttivoCircolante"],                                                                          "i"),
    "Ratei Attivi":                 (["AttivoRateiRisconti"],                                                                             "i"),
    "Totale Attivo":                (["TotaleAttivo"],                                                                                    "i"),
    # ── Stato Patrimoniale Passivo ──
    "Capitale Sociale":             (["PatrimonioNettoCapitale"],                                                                         "i"),
    "Riserva Legale":               (["PatrimonioNettoRiservaLegale"],                                                                    "i"),
    "Altre Riserve":                (["PatrimonioNettoAltreRiserveDistintamenteIndicateTotaleAltreRiserve"],                               "i"),
    "Utile PN":                     (["PatrimonioNettoUtilePerditaEsercizio"],                                                             "i"),
    "Tot. Patrimonio Netto":        (["TotalePatrimonioNetto"],                                                                           "i"),
    "Fondi Rischi":                 (["TotaleFondiRischiOneri"],                                                                          "i"),
    "TFR":                          (["TrattamentoFineRapportoLavoroSubordinato"],                                                         "i"),
    "Debiti Banche":                (["DebitiDebitiVersoBancheTotaleDebitiVersoBanche"],                                                   "i"),
    "Debiti Altri Finanziatori":    (["DebitiDebitiVersoAltriFinanziatoriTotaleDebitiVersoAltriFinanziatori"],                             "i"),
    "Debiti Fornitori":             (["DebitiDebitiVersoFornitoriTotaleDebitiVersoFornitori"],                                             "i"),
    "Debiti Tributari":             (["DebitiDebitiTributariTotaleDebitiTributari"],                                                      "i"),
    "Debiti Previdenza":            (["DebitiDebitiVersoIstitutiPrevidenzaSicurezzaSocialeTotaleDebitiVersoIstitutiPrevidenzaSicurezzaSociale"], "i"),
    "Altri Debiti":                 (["DebitiAltriDebitiTotaleAltriDebiti"],                                                               "i"),
    "Tot. Debiti":                  (["TotaleDebiti"],                                                                                    "i"),
    "Ratei Passivi":                (["PassivoRateiRisconti"],                                                                            "i"),
