def estrai(root, tags, anno, tipo):
    ctx = f"c{anno}_{tipo}"
    for t in tags:
        for elem in root.iter(f"{{{NS}}}{t}"):
            if elem.get("contextRef") == ctx:
                try:
                    return float(elem.text)
                except (TypeError, ValueError):
                    pass
    return None

print("Lettura XBRL...")
D = {k: {} for k in TAGS}
for anno in anni:
    path = os.path.join(docs_dir, file_anni[anno])
    root = ET.parse(path).getroot()
    print(f"  OK {file_anni[anno]}")
    for voce, (tags, tipo) in TAGS.items():
        D[voce][anno] = estrai(root, tags, anno, tipo)

def G(voce, anno):
    return D.get(voce, {}).get(anno)

# ==================== FORMATTAZIONE ====================
def fmt_e(v, zero_dash=False):
    if v is None:
        return "<span class='nd'>—</span>"
    if zero_dash and v == 0:
        return "<span class='nd'>—</span>"
    s = f"{v:,.0f}".replace(",", ".")
    if v < 0:
        return f"<span class='neg'>({s.replace('-','')})</span>"
    return s

def fmt_delta(curr, prev):
    if curr is None or prev is None or prev == 0:
        return "<span class='nd'>—</span>"
    d = (curr - prev) / abs(prev) * 100
    cls   = "pos" if d > 0 else ("neg" if d < 0 else "nd")
    arrow = "▲" if d > 0 else ("▼" if d < 0 else "")
    return f"<span class='{cls}'>{arrow} {abs(d):.1f}%</span>"

