# ==================== BUILDER TABELLE ====================
show_delta   = len(anni) > 1
compare_pair = (anni[-2], anni[-1]) if show_delta else None

def build_rows(rows_def):
    html = ""
    for (lbl, key, indent, bold, sep, hl, hl_ebit) in rows_def:
        vals = {a: G(key, a) for a in anni} if key else {a: None for a in anni}

        row_cls = "tr-voce"
        if bold:              row_cls += " tr-bold"
        if sep:               row_cls += " tr-sep"
        if hl:                row_cls += " tr-highlight"
        if hl_ebit:           row_cls += " tr-ebit"
        if indent == 0 and not key and bold: row_cls += " tr-section"

        pad = f"padding-left:{16 + indent * 22}px"

        td_vals = "".join(
            f"<td class='td-num'>{fmt_e(vals[a], zero_dash=not bold)}</td>"
            for a in anni
        )
        td_delta = ""
        if show_delta:
            td_delta = f"<td class='td-delta'>{fmt_delta(vals[compare_pair[1]], vals[compare_pair[0]])}</td>"

        html += f"""
<tr class="{row_cls}">
  <td class="td-label" style="{pad}">{lbl}</td>
  {td_vals}
  {td_delta}
</tr>"""
    return html

def build_table(title, section_label, rows_def):
