    </table>
  </div>
  <div class="table-note">Valori in Euro (€) · Bilancio redatto ai sensi del D.Lgs. 127/91</div>
</div>"""

ce_html         = build_table("Conto Economico",              "VOCE",    CE)
sp_attivo_html  = build_table("Stato Patrimoniale — ATTIVO",  "ATTIVO",  SP_ATTIVO)
