def estrai_valore(root, tag_locale, anno, tipo):
    full_tag = f"{{{NS}}}{tag_locale}"
    ctx = f"c{anno}_{tipo}"
    for elem in root.iter(full_tag):
        if elem.get("contextRef") == ctx:
            try:
                return float(elem.text)
            except (TypeError, ValueError):
                pass
    return None

