# ── Calcoli ────────────────────────────────────────────────────────────────────
def ebitda(anno):
    e = dati["EBIT"].get(anno)
    a = dati["Ammortamenti"].get(anno)
    return (e + a) if (e is not None and a is not None) else None

def pfn(anno):
    db = dati["Debiti Banche Totale"].get(anno)
    lq = dati["Liquidita"].get(anno)
    return (db - lq) if (db is not None and lq is not None) else None

def pfn_ebitda_val(anno):
    p = pfn(anno)
    e = ebitda(anno)
    return round(p / e, 2) if (p is not None and e and e > 0) else None

def costo_denaro_pct(anno):
    of = dati["Oneri Finanziari"].get(anno)
    db = dati["Debiti Banche Totale"].get(anno)
    if of is None or db is None or db == 0:
        return None
    return round(abs(of) / abs(db) * 100, 2)

def incidenza(voce, anno):
    r = dati["Ricavi Totali"].get(anno)
    c = dati[voce].get(anno)
    return round(c / r * 100, 1) if (r and c) else None

def inc_list(voce):
    return [incidenza(voce, a) for a in anni]

def gg_incasso(anno):
    cr = dati["Crediti Clienti"].get(anno)
    rv = dati["Ricavi Vendite"].get(anno)
    return round(cr / (rv / 365)) if (cr and rv) else None

def gg_pagamento(anno):
    db = dati["Debiti Fornitori"].get(anno)
    cm = dati["Costi Materie Prime"].get(anno)
    return round(db / (cm / 365)) if (db and cm) else None

def gg_magazzino(anno):
    rm = dati["Rimanenze"].get(anno)
    cm = dati["Costi Materie Prime"].get(anno)
    return round(rm / (cm / 365)) if (rm and cm) else None

def fmt(v):
    return "N/D" if v is None else f"€ {v:,.0f}".replace(",", ".")

