def fill(hex_c, a=0.10):
    h = hex_c.lstrip("#")
    r, g, b = (int(h[i:i+2], 16) for i in (0, 2, 4))
    return f"rgba({r},{g},{b},{a})"

def lighten(hex_c, f=0.55):
    h = hex_c.lstrip("#")
    r, g, b = (int(h[i:i+2], 16) for i in (0, 2, 4))
    return "#{:02x}{:02x}{:02x}".format(
        min(255, int(r + (255 - r) * f)),
        min(255, int(g + (255 - g) * f)),
        min(255, int(b + (255 - b) * f)),
    )

def base_layout(title="", h=300):
    return dict(
        title=dict(
            text=title,
            font=dict(size=12, color="#3a5a7c", family=FONT_FAM),
            x=0, xanchor="left",
            pad=dict(l=0, b=8),
        ),
        plot_bgcolor=BG_PLOT,
        paper_bgcolor=BG_PLOT,
        height=h,
        margin=dict(l=80, r=70, t=48, b=40),
        font=dict(family=FONT_FAM, size=10, color="#1a3a5c"),
        showlegend=False,
        hovermode="x unified",
        hoverlabel=dict(
            bgcolor="#0d2e52",
            bordercolor="#0d2e52",
            font=dict(color="white", size=10, family=FONT_FAM),
        ),
        xaxis=dict(
            tickmode="array",
            tickvals=anni,
            ticktext=[str(a) for a in anni],
            showgrid=False,
            zeroline=False,
            showline=False,
            tickfont=dict(size=10, color=TICK_COL),
        ),
        yaxis=dict(
            showgrid=True,
            gridcolor=GRID_COL,
            zeroline=False,
            showline=False,
            tickfont=dict(size=9, color=TICK_COL),
            tickprefix="€ ",
            tickformat=",.0f",
        ),
    )

def yaxis2_style(colore_sb):
    return dict(
        overlaying="y",
        side="right",
        ticksuffix="%",
        showgrid=False,
        zeroline=False,
        showline=False,
        tickfont=dict(size=9, color=colore_sb),
    )

def set_yrange(fig, vals, pad=1.22, axis="yaxis"):
    valid = [v for v in vals if v is not None]
    if valid:
        getattr(fig.layout, axis).range = [0, max(valid) * pad]

