charts = {}

def make_sparkline_pct(voce, colore, title):
    vals = [dati[voce].get(a) for a in anni]
    incs = inc_list(voce)
    csb  = lighten(colore, 0.52)
    fig = go.Figure()
    fig.add_scatter(
        x=anni, y=vals, mode="lines+markers",
        line=dict(color=colore, width=2.5, shape="spline"),
        marker=dict(size=7, color=colore, line=dict(color=BG_PLOT, width=1.5)),
        fill="tozeroy", fillcolor=fill(colore, 0.09),
        name=voce, yaxis="y",
    )
    fig.add_scatter(
        x=anni, y=incs, mode="lines+markers",
        line=dict(color=csb, width=1.5, shape="spline", dash="dot"),
        marker=dict(size=5, color=csb, symbol="diamond"),
        name="% su ricavi", yaxis="y2",
    )
    ly = base_layout(title, h=300)
    ly["yaxis2"] = yaxis2_style(csb)
    fig.update_layout(**ly)
    set_yrange(fig, vals)
    return fig

def make_area(vals, colore, title, giorni=False, verde=False):
    fc = VFILL if verde else fill(colore, 0.09)
    lc = VERDE if verde else colore
    fig = go.Figure()
    fig.add_scatter(
        x=anni, y=vals, mode="lines+markers",
        line=dict(color=lc, width=2.5, shape="spline"),
        marker=dict(size=7, color=lc, line=dict(color=BG_PLOT, width=1.5)),
        fill="tozeroy", fillcolor=fc, name=title,
    )
    ly = base_layout(title, h=300)
    if giorni:
        ly["yaxis"]["tickprefix"] = ""
        ly["yaxis"]["ticksuffix"] = " gg"
    fig.update_layout(**ly)
    set_yrange(fig, vals)
    return fig

